// This implementation uses a constrained decoding strategy to generate first-order logic (FOL) formulas.
// It ensures that the generated prefixes are valid FOL statements by using the parser and constraints.
// The strategy alternates between unconstrained and constrained steps, rolling back to a valid prefix if necessary.
// The loop continues until the maximum number of steps is reached or a complete FOL statement is generated.
// CSD_RATIONALE_END

generated := [];
while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  var validTokens := parser.ValidNextTokens(generated);
  var hasValid := exists token :: token in validTokens && parser.ValidNextToken(generated, token);

  if hasValid && !parser.IsCompletePrefix(generated)
  {
    // Constrained step: use ConstrainedStep to generate a valid next token
    var next, newSteps := helpers.ConstrainedStep(lm, parser, prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;
  }
  else
  {
    // Unconstrained step: use UnconstrainedStep to generate a random token
    var next, newSteps := helpers.UnconstrainedStep(lm, prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;
  }

  // If the prefix becomes invalid, roll it back to a valid prefix
  if !parser.IsValidPrefix(generated)
